const MiniRecorder: React.FC<{onTranscriptChange: (transcript: string) => void}> = ({ onTranscriptChange }) => {
    const [isRecording, setIsRecording] = useState(false);
    const [error, setError] = useState<string|null>(null);
    const liveTranscriptRef = useRef('');
    const sessionPromiseRef = useRef<Promise<LiveSession> | null>(null);
    const mediaStreamRef = useRef<MediaStream | null>(null);
    const audioContextRef = useRef<AudioContext | null>(null);

    const start = async () => {
        if (isRecording) return;
        liveTranscriptRef.current = '';
        onTranscriptChange('');
        setError(null);

        const ai = getGeminiInstance();
        if (!ai) {
          setError("AI client not available.");
          return;
        }

        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            mediaStreamRef.current = stream;
            setIsRecording(true);

            // Create AudioContext with native rate
            const context = new (window.AudioContext || (window as any).webkitAudioContext)();
            audioContextRef.current = context;

            if (context.state === 'suspended') {
                await context.resume();
            }

            const sourceSampleRate = context.sampleRate;
            const targetSampleRate = 16000;

            sessionPromiseRef.current = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-09-2025',
                callbacks: {
                  onopen: () => {
                    const source = context.createMediaStreamSource(stream);
                    const scriptProcessor = context.createScriptProcessor(4096, 1, 1);
                    scriptProcessor.onaudioprocess = (e) => {
                      const inputData = e.inputBuffer.getChannelData(0);

                      // Manual Downsample
                      const ratio = sourceSampleRate / targetSampleRate;
                      const newLength = Math.floor(inputData.length / ratio);
                      const int16 = new Int16Array(newLength);

                      for (let i = 0; i < newLength; i++) {
                        const start = Math.floor(i * ratio);
                        const end = Math.floor((i + 1) * ratio);
                        let sum = 0; 
                        let count = 0;
                        for (let j = start; j < end && j < inputData.length; j++) {
                            sum += inputData[j]; 
                            count++;
                        }
                        const avg = count > 0 ? sum / count : 0;
                        int16[i] = Math.max(-32768, Math.min(32767, avg * 32768));
                      }

                      let binary = '';
                      const bytes = new Uint8Array(int16.buffer);
                      for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
