// Vercel Serverless Function for /api/sync
// NOTE: On Vercel, in-memory variables like 'db' DO NOT PERSIST between requests.
// To make Sync work on Vercel, you must connect a database (like Vercel KV or Firebase).
// For now, this will return success but data won't actually persist across device reloads unless you use the Export/Import feature.

export default async function handler(req, res) {
  // Allow CORS
  res.setHeader('Access-Control-Allow-Credentials', true);
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,OPTIONS,PATCH,DELETE,POST,PUT');
  res.setHeader(
    'Access-Control-Allow-Headers',
    'X-CSRF-Token, X-Requested-With, Accept, Accept-Version, Content-Length, Content-MD5, Content-Type, Date, X-Api-Version'
  );

  if (req.method === 'OPTIONS') {
    res.status(200).end();
    return;
  }

  const { syncId } = req.query;

  if (!syncId) {
    return res.status(400).json({ error: 'Missing syncId' });
  }

  if (req.method === 'GET') {
    // Without a real DB, we return an empty structure so the app falls back to local data
    return res.status(200).json({ memories: [], courses: [] });
  }

  if (req.method === 'POST') {
    // Acknowledge the save so the app doesn't show an error, 
    // but log that persistent storage isn't configured.
    console.log(`Received data for syncId: ${syncId}. (Not persisted - requires Vercel KV)`);
    return res.status(200).send('Data received (Ephemeral Mode)');
  }

  return res.status(405).json({ error: 'Method Not Allowed' });
}
