import { useState, useEffect, useCallback, useRef } from 'react';
import type { AnyMemory, WebMemory } from '../types';

// Debounce hook
const useDebounce = (callback: (...args: any[]) => void, delay: number) => {
    const timeoutRef = useRef<number | null>(null);
    return (...args: any[]) => {
        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
        }
        timeoutRef.current = window.setTimeout(() => {
            callback(...args);
        }, delay);
    };
};

interface SharedClip {
    key: string;
    data: {
        id: string;
        url: string;
        title: string;
        content: string;
        date: string;
    };
}

export interface StoredData {
    memories: AnyMemory[];
    courses: string[];
}
const LOCAL_STORAGE_KEY = 'second-brain-data';

export const useRecordings = (syncId: string | null) => {
    const [memories, setMemories] = useState<AnyMemory[]>([]);
    const [courses, setCourses] = useState<string[]>([]);
    const [isSyncing, setIsSyncing] = useState(false);
    const [isOffline, setIsOffline] = useState(false);
    const [pendingClipsCount, setPendingClipsCount] = useState(0);

    // Load initial data from local storage
    useEffect(() => {
        try {
            const localData = localStorage.getItem(LOCAL_STORAGE_KEY);
            if (localData) {
                const parsed: StoredData = JSON.parse(localData);
                setMemories(parsed.memories || []);
                setCourses(parsed.courses || []);
            }
        } catch (error) {
            console.error("Failed to load data from local storage", error);
        }
    }, []);

    // Persist to local storage whenever data changes
    useEffect(() => {
        try {
            const data: StoredData = { memories, courses };
            localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(data));
        } catch (error) {
            console.error("Failed to save data to local storage", error);
        }
    }, [memories, courses]);

    // Vercel Sync Logic:
    // Since Vercel functions are ephemeral (stateless) without a connected DB like Redis/Postgres,
    // they cannot store our JSON data file. 
    // We disable the "Pull" logic if the server returns empty data, trusting Local Storage instead.

    const pushToRemote = useCallback(async (data: StoredData) => {
        if (!syncId || isSyncing || isOffline) return;
        setIsSyncing(true);
        try {
            // We still fire the push event so that if you DO add a database later, it works.
            // For now, it just hits the ephemeral API.
            await fetch(`/api/sync?syncId=${syncId}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data),
            });
        } catch (error) {
            console.warn("Sync endpoint unreachable (Offline Mode active)");
            setIsOffline(true);
        } finally {
            setIsSyncing(false);
        }
    }, [syncId, isSyncing, isOffline]);

    const debouncedPush = useDebounce(pushToRemote, 2000);

    useEffect(() => {
        if (syncId && !isOffline) {
            debouncedPush({ memories, courses });
        }
    }, [memories, courses, syncId, debouncedPush, isOffline]);

    useEffect(() => {
        const pullFromRemote = async () => {
            if (!syncId || isOffline) return;
            setIsSyncing(true);
            try {
                const response = await fetch(`/api/sync?syncId=${syncId}`);
                if (!response.ok) {
                     // If API fails (e.g. 404 or 500), go offline
                     setIsOffline(true);
                     return;
                }

                const data: StoredData = await response.json();

                // CRITICAL SAFETY CHECK for Vercel Ephemeral Mode:
                // If the server returns empty data (because it forgot everything), 
                // BUT we have local data, DO NOT OVERWRITE our local data with empty arrays.
                // Instead, treat it as a "fresh server" and push our data up.
                const remoteHasData = data.memories && data.memories.length > 0;
                const localHasData = memories.length > 0;

                if (remoteHasData) {
                    // Normal sync: Server has data, so we use it.
                    setMemories(data.memories || []);
                    setCourses(data.courses || []);
                } else if (localHasData && !remoteHasData) {
                    // Safety: Server is empty, we are not. Push our data to initialize server.
                    console.log("Remote is empty, pushing local data...");
                    pushToRemote({ memories, courses });
                }
            } catch (error) {
                console.warn("Sync failed, switching to local mode.");
                setIsOffline(true);
            } finally {
                setIsSyncing(false);
            }
        };
        pullFromRemote();
    }, [syncId]);

    // ... (Rest of the hook remains the same) ...

    // Stub out clips fetching for Vercel ephemeral mode to prevent 404 loops
    const fetchPendingClipsCount = useCallback(async () => {
        // In ephemeral mode, clips vanish instantly, so we skip polling to save bandwidth
        setPendingClipsCount(0); 
    }, []);

    useEffect(() => {
        // fetchPendingClipsCount(); // Disabled polling for Vercel MVP
    }, [fetchPendingClipsCount]);

    const addMemory = useCallback(async (memory: Omit<AnyMemory, 'id' | 'date'>) => {
        const newMemory: AnyMemory = {
            ...memory,
            id: crypto.randomUUID(),
            date: new Date().toISOString(),
        } as unknown as AnyMemory;
        setMemories(prev => [newMemory, ...prev].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    }, []);

    const syncSharedClips = useCallback(async (): Promise<number> => {
        return 0; // Disabled for Vercel MVP
    }, []);

    const deleteMemory = useCallback(async (id: string) => {
        setMemories(prev => prev.filter(m => m.id !== id));
    }, []);

    const bulkDeleteMemories = useCallback(async (ids: string[]) => {
        const idSet = new Set(ids);
        setMemories(prev => prev.filter(m => !idSet.has(m.id)));
    }, []);

    const updateMemory = useCallback(async (id: string, updates: Partial<AnyMemory>) => {
        setMemories(prev => prev.map(m => m.id === id ? { ...m, ...updates } as unknown as AnyMemory : m));
    }, []);

    const addCourse = useCallback(async (courseName: string) => {
        if (!courseName.trim()) return;
        setCourses(prev => [...new Set([...prev, courseName.trim()])]);
    }, []);

    const loadBackup = useCallback((data: StoredData) => {
        if (data.memories) setMemories(data.memories);
        if (data.courses) setCourses(data.courses);
        localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(data));
    }, []);

    return { memories, addMemory, deleteMemory, bulkDeleteMemories, updateMemory, syncSharedClips, pendingClipsCount, courses, addCourse, isSyncing, loadBackup };
};
]]></content>
