            const prevSegment = index > 0 ? lecture.structuredTranscript[index - 1] : null;

            if (!prevSegment || segment.speakerId !== prevSegment.speakerId) {
                return `${index > 0 ? '\n\n' : ''}${speakerLabel}: ${segment.text}`;
            }
            return segment.text;
        }).join('');

        onUpdate(lecture.id, {
