                : courseMemories.map(mem => (
                        <div key={mem.id} onClick={() => handleSelectItem(mem)} className="bg-gray-800 p-4 rounded-lg shadow-md border border-gray-700 cursor-pointer hover:border-blue-500 transition-colors">
